SELECT SUM(total_credits) AS total_credits_earned
FROM total_credits
WHERE year = 2022;

SELECT student_id, SUM(total_credits) AS total_credits_earned
FROM total_credits
GROUP BY student_id;

SELECT total_credits AS "Total Credits"
FROM total_credits
WHERE student_id = 1;

SELECT MAX(total_credits) AS max_credits
FROM total_credits
WHERE year = 2022;
